package org.apache.commons.math3.distribution;

import java.util.ArrayList;
import java.util.List;

import org.apache.commons.math3.exception.MathArithmeticException;
import org.apache.commons.math3.exception.MathIllegalArgumentException;
import org.apache.commons.math3.exception.NotPositiveException;
import org.apache.commons.math3.exception.NotStrictlyPositiveException;
import org.apache.commons.math3.exception.util.LocalizedFormats;
import org.apache.commons.math3.random.RandomGenerator;
import org.apache.commons.math3.random.Well19937c;
import org.apache.commons.math3.util.MathArrays;
import org.apache.commons.math3.util.Pair;

/**
 * Generic implementation of the discrete distribution.
 *
 * @param <T> type of the random variable.
 * @see <a href="http://en.wikipedia.org/wiki/Probability_distribution#Discrete_probability_distribution">Discrete probability distribution (Wikipedia)</a>
 * @see <a href="http://mathworld.wolfram.com/DiscreteDistribution.html">Discrete Distribution (MathWorld)</a>
 * @version $Id: DiscreteDistribution.java 169 2013-03-08 09:02:38Z wydrych $
 */
public class DiscreteDistribution<T> {

    /**
     * RNG instance used to generate samples from the distribution.
     */
    protected final RandomGenerator random;
    /**
     * List of random variable values.
     */
    private final List<T> singletons;
    /**
     * Normalized array of probabilities of respective random variable values.
     */
    private final double[] probabilities;

    /**
     * Create a discrete distribution using the given probability mass function
     * definition.
     *
     * @param samples definition of probability mass function in the format of
     * list of pairs.
     * @throws NotPositiveException if probability of at least one value is
     * negative.
     * @throws MathArithmeticException if the probabilities sum to zero.
     * @throws MathIllegalArgumentException if probability of at least one value
     * is infinite.
     */
    public DiscreteDistribution(final List<Pair<T, Double>> samples)
        throws NotPositiveException, MathArithmeticException, MathIllegalArgumentException {
        this(new Well19937c(), samples);
    }

    /**
     * Create a discrete distribution using the given random number generator
     * and probability mass function definition.
     *
     * @param rng random number generator.
     * @param samples definition of probability mass function in the format of
     * list of pairs.
     * @throws NotPositiveException if probability of at least one value is
     * negative.
     * @throws MathArithmeticException if the probabilities sum to zero.
     * @throws MathIllegalArgumentException if probability of at least one value
     * is infinite.
     */
    public DiscreteDistribution(final RandomGenerator rng, final List<Pair<T, Double>> samples)
        throws NotPositiveException, MathArithmeticException, MathIllegalArgumentException {
        random = rng;

        singletons = new ArrayList<T>(samples.size());
        final double[] probs = new double[samples.size()];

        for (int i = 0; i < samples.size(); i++) {
            final Pair<T, Double> sample = samples.get(i);
            singletons.add(sample.getKey());
            if (sample.getValue() < 0) {
                throw new NotPositiveException(sample.getValue());
            }
            probs[i] = sample.getValue();
        }

        probabilities = MathArrays.normalizeArray(probs, 1.0);
    }

    /**
     * Reseed the random generator used to generate samples.
     *
     * @param seed the new seed
     */
    public void reseedRandomGenerator(long seed) {
        random.setSeed(seed);
    }

    /**
     * For a random variable {@code X} whose values are distributed according to
     * this distribution, this method returns {@code P(X = x)}. In other words,
     * this method represents the probability mass function (PMF) for the
     * distribution.
     *
     * @param x the point at which the PMF is evaluated
     * @return the value of the probability mass function at {@code x}
     */
    double probability(final T x) {
        double probability = 0;

        for (int i = 0; i < probabilities.length; i++) {
            if ((x == null && singletons.get(i) == null) ||
                (x != null && x.equals(singletons.get(i)))) {
                probability += probabilities[i];
            }
        }

        return probability;
    }

    /**
     * Return the definition of probability mass function in the format of list
     * of pairs.
     *
     * @return definition of probability mass function.
     */
    public List<Pair<T, Double>> getSamples() {
        final List<Pair<T, Double>> samples = new ArrayList<Pair<T, Double>>(probabilities.length);

        for (int i = 0; i < probabilities.length; i++) {
            samples.add(new Pair<T, Double>(singletons.get(i), probabilities[i]));
        }

        return samples;
    }

    /**
     * Generate a random value sampled from this distribution.
     *
     * @return a random value.
     */
    public T sample() {
        final double randomValue = random.nextDouble();
        double sum = 0;

        for (int i = 0; i < probabilities.length; i++) {
            sum += probabilities[i];
            if (randomValue < sum) {
                return singletons.get(i);
            }
        }

        /* This should never happen, but it ensures we will return a correct
         * object in case the loop above has some floating point inequality
         * problem on the final iteration. */
        return singletons.get(singletons.size() - 1);
    }

    /**
     * Generate a random sample from the distribution.
     *
     * @param sampleSize the number of random values to generate.
     * @return an array representing the random sample.
     * @throws NotStrictlyPositiveException if {@code sampleSize} is not
     * positive.
     */
    public T[] sample(int sampleSize) throws NotStrictlyPositiveException {
        if (sampleSize <= 0) {
            throw new NotStrictlyPositiveException(LocalizedFormats.NUMBER_OF_SAMPLES,
                    sampleSize);
        }

        final T[]out = (T[]) java.lang.reflect.Array.newInstance(singletons.get(0).getClass(), sampleSize);

        for (int i = 0; i < sampleSize; i++) {
            out[i] = sample();
        }

        return out;

    }

}

package org.apache.commons.math3.distribution.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.apache.commons.math3.distribution.DiscreteDistribution;
import org.apache.commons.math3.util.Pair;
import static org.junit.Assert.*;
import java.util.List;
import java.util.Arrays;
import java.util.ArrayList;

public class StepDefs {

    private Object firstObject;
    private Object secondObject;
    private List<Pair<Object, Double>> samples;
    private DiscreteDistribution<Object> distribution;
    private Object[] result;
    private boolean arrayStoreExceptionThrown = false;

    @Given("a list of samples containing two different anonymous Objects")
    public void a_list_of_samples_containing_two_different_anonymous_Objects() {
        firstObject = new Object() {
            @Override
            public String toString() {
                return "FirstObject";
            }
        };
        secondObject = new Object() {
            @Override
            public String toString() {
                return "SecondObject";
            }
        };
    }

    @Given("the first object has a probability of 0.0")
    public void the_first_object_has_a_probability_of_0_0() {
        // This step is part of the given condition
        assertTrue("First object should exist", firstObject != null);
    }

    @Given("the second object has a probability of 1.0")
    public void the_second_object_has_a_probability_of_1_0() {
        // This step is part of the given condition
        assertTrue("Second object should exist", secondObject != null);

        // Create the list of samples with probabilities
        samples = new ArrayList<>();
        samples.add(new Pair<>(firstObject, 0.0));
        samples.add(new Pair<>(secondObject, 1.0));
    }

    @When("a DiscreteDistribution is created with these samples")
    public void a_discrete_distribution_is_created_with_these_samples() {
        try {
            // Attempt to create a DiscreteDistribution with heterogeneous samples
            distribution = new DiscreteDistribution<>(samples);
        } catch (ArrayStoreException e) {
            arrayStoreExceptionThrown = true;
        } catch (Exception e) {
            // Catch any other exception that could occur due to heterogeneous types
            if (e.getClass().getSimpleName().equals("ArrayStoreException")) {
                arrayStoreExceptionThrown = true;
            }
        }
    }

    @When("I request a sample of size 1")
    public void i_request_a_sample_of_size_1() {
        if (!arrayStoreExceptionThrown && distribution != null) {
            try {
                // Note: The sample method returns an array of the generic type
                result = distribution.sample(1);
            } catch (ArrayStoreException e) {
                arrayStoreExceptionThrown = true;
            } catch (Exception e) {
                // Catch any other exception that could occur due to heterogeneous types
                if (e.getClass().getSimpleName().equals("ArrayStoreException")) {
                    arrayStoreExceptionThrown = true;
                }
            }
        }
    }

    @Then("the operation should successfully return an array of length 1")
    public void the_operation_should_successfully_return_an_array_of_length_1() {
        if (arrayStoreExceptionThrown) {
            fail("ArrayStoreException was thrown, which should not happen");
        }
        assertNotNull("Result array should not be null", result);
        assertEquals("Result array should have length 1", 1, result.length);
    }

    @Then("the operation should not throw an ArrayStoreException")
    public void the_operation_should_not_throw_an_array_store_exception() {
        assertFalse("ArrayStoreException should not be thrown", arrayStoreExceptionThrown);
    }
}

