/**
 * Generate a random sample from the distribution.
 *
 * @param sampleSize the number of random values to generate.
 * @return an array representing the random sample.
 * @throws NotStrictlyPositiveException if {@code sampleSize} is not
 * positive.
 */
public T[] sample(int sampleSize) throws NotStrictlyPositiveException {
    if (sampleSize <= 0) {
        throw new NotStrictlyPositiveException(LocalizedFormats.NUMBER_OF_SAMPLES,
                sampleSize);
    }

    // Use Object.class to prevent ArrayStoreException when dealing with heterogeneous types
    final T[] out = (T[]) java.lang.reflect.Array.newInstance(
        getArrayComponentType(), sampleSize);

    for (int i = 0; i < sampleSize; i++) {
        out[i] = sample();
    }

    return out;

}

/**
 * Determine the appropriate component type for the output array.
 * If all singleton objects are of the same type, return that type.
 * Otherwise, return Object.class to handle heterogeneous types safely.
 * 
 * @return the component type for the output array
 */
@SuppressWarnings("unchecked")
private Class<T> getArrayComponentType() {
    if (singletons.isEmpty()) {
        return (Class<T>) Object.class;
    }

    Class<?> firstClass = singletons.get(0).getClass();
    for (T singleton : singletons) {
        if (!firstClass.equals(singleton.getClass())) {
            // Found different types, use Object.class to avoid ArrayStoreException
            return (Class<T>) Object.class;
        }
    }

    // All objects are of the same type
    return (Class<T>) firstClass;
}

